import crypto from 'crypto';
import { Repository } from 'typeorm';
import { AppDataSource } from '../data-source';
import { FinancialStatement } from '../entities/financial-statement.entity';
import { SharableLink } from '../entities/sharable-link.entity';

export class FinancialStatementNotFoundError extends Error {
  constructor() {
    super('Financial statement not found');
    this.name = 'FinancialStatementNotFoundError';
  }
}

export class SharableLinkNotFoundError extends Error {
  constructor() {
    super('Sharable link not found');
    this.name = 'SharableLinkNotFoundError';
  }
}

export class SharableLinkExpiredError extends Error {
  constructor() {
    super('Sharable link has expired');
    this.name = 'SharableLinkExpiredError';
  }
}

const DEFAULT_EXPIRY_MS = 7 * 24 * 60 * 60 * 1000;

const getSharableLinkRepository = (): Repository<SharableLink> =>
  AppDataSource.getRepository(SharableLink);

const getFinancialStatementRepository = (): Repository<FinancialStatement> =>
  AppDataSource.getRepository(FinancialStatement);

export interface CreateSharableLinkOptions {
  financialStatementId: number;
  expiresInMs?: number;
}

export const generateToken = (): string => crypto.randomBytes(32).toString('base64url');

export const createSharableLink = async (
  options: CreateSharableLinkOptions,
): Promise<SharableLink> => {
  const statementRepo = getFinancialStatementRepository();
  const statement = await statementRepo.findOne({
    where: { id: options.financialStatementId },
  });
  if (!statement) {
    throw new FinancialStatementNotFoundError();
  }

  const expiresInMs = options.expiresInMs ?? DEFAULT_EXPIRY_MS;
  const repo = getSharableLinkRepository();
  const link = repo.create({
    financialStatementId: statement.id,
    token: generateToken(),
    expiresAt: new Date(Date.now() + expiresInMs),
  });

  return repo.save(link);
};

export const findSharableLinkByToken = async (token: string): Promise<SharableLink> => {
  const repo = getSharableLinkRepository();
  const link = await repo.findOne({
    where: { token },
    relations: { financialStatement: true },
  });

  if (!link) {
    throw new SharableLinkNotFoundError();
  }

  if (link.expiresAt.getTime() <= Date.now()) {
    throw new SharableLinkExpiredError();
  }

  return link;
};
